import json

def analyze_logs(filepath):
    with open(filepath) as f:
        lines = f.readlines()
    parsed = []
    for line in lines:
        try:
            parsed.append(json.loads(line))
        except:
            pass
    errors = [p for p in parsed if p.get('level') == 'ERROR']
    by_service = {}
    for e in errors:
        s = e.get('service', 'unknown')
        if s not in by_service:
            by_service[s] = []
        by_service[s].append(e)
    return by_service
